</i>
</small>"},"$:/language/Notifications/CreateTiddler":{"title":"$:/language/Notifications/CreateTiddler","text":"Created!"},"$:/language/Notifications/RemoveTiddler":{"title":"$:/language/Notifications/RemoveTiddler","text":"Removed!"},"$:/language/Notifications/ctagEmpty":{"title":"$:/language/Notifications/ctagEmpty","text":"Ctag value can't be empty!"},"$:/language/Notifications/noSubtiddler":{"title":"$:/language/Notifications/noSubtiddler","text":"No subtiddler!"},"$:/language/Notifications/topicExists":{"title":"$:/language/Notifications/topicExists","text":"The topic already exists!"},"$:/language/xp/aggregation/ClickPopup":{"title":"$:/language/xp/aggregation/ClickPopup","text":"<style>
