"},"$:/aggregation/macros/list":{"title":"$:/aggregation/macros/list","tags":"$:/tags/Macro","text":"\define aggr-preset-ctags(categoryPrefix)
<$list filter="[all[shadows+tiddlers]prefix<__categoryPrefix__>!has[draft.of]has[text]]" variable="listItem">
<$list filter="[<listItem>get[text]]"/>
</$list>
\end

\define aggr-list-thumbnails(tag,ctag,categoryPrefix,width:"220",height:"123")
<$vars aggregationTag=<<__tag__>>>
<$wikify text=<<aggr-preset-ctags>> name="presetCtags">

<div class="box-list-tags">
  <$list filter="[<__ctag__>]">
    <$transclude tiddler="$:/xp/ui/TagTemplate/aggregation"/>
  </$list>
  <$list filter="[tag<__tag__>tag<__ctag__>tags[]] -[<__tag__>] -[<__ctag__>] -[enlist<presetCtags>] +[limit[1]]">
    <span class="xp-tag-divider"></span>
  </$list>
  <$list filter="[tag<__tag__>tag<__ctag__>tags[]sort[]] -[<__tag__>] -[<__ctag__>] -[enlist<presetCtags>]">
    <span class="tc-tag-list-item">
      <$set name="transclusion" value=<<currentTiddler>>>
      <$macrocall $name="tag-pill-body" tag=<<currentTiddler>> icon={{!!icon}} colour={{!!color}} palette={{$:/palette}} element-tag="""$button""" element-attributes="""popup=<<qualify "$:/state/popup/tag">> dragFilter='[all[current]tagging[]]' tag='span'"""/>
      <$reveal state=<<qualify "$:/state/popup/tag">> type="popup" position="below" animate="yes" class="tc-drop-down">
      <$set name="tv-show-missing-links" value="yes">
      <$transclude tiddler="$:/core/ui/ListItemTemplate"/>
      </$set>
      <$list filter="[all[shadows+tiddlers]tag[$:/tags/TagDropdown]!has[draft.of]]" variable="listItem"> 
      <$transclude tiddler=<<listItem>>/> 
      </$list>
      <hr>
      <$macrocall $name="list-tagged-draggable" tag=<<currentTiddler>> subFilter="tag<__tag__>tag<__ctag__>"/>
      </$reveal>
      </$set>
    </span>
  </$list>
</div>

<div style="font-size:0.7em;text-align:left;margin-top:2em;margin-bottom:2em;">
<<list-thumbnails filter:"[tag<__tag__>tag<__ctag__>!has[draft.of]sort[]]" width:"$width$" height:"$height$">>
</div>

</$wikify>
</$vars>
\end

\define aggr-links-popup(tag,ctag,categoryPrefix)
<$vars aggregationTag=<<__tag__>>>
<$wikify text=<<aggr-preset-ctags>> name="presetCtags">

<div class="box-list-tags">
  <$list filter=<<__ctag__>>>
    <$transclude tiddler="$:/xp/ui/TagTemplate/aggregation"/>
  </$list>
  <$list filter="[tag<__tag__>tag<__ctag__>tags[]] -[<__tag__>] -[<__ctag__>] -[enlist<presetCtags>] +[limit[1]]">
    <span class="xp-tag-divider"></span>
  </$list>
  <$list filter="[tag<__tag__>tag<__ctag__>tags[]sort[]] -[<__tag__>] -[<__ctag__>] -[enlist<presetCtags>]">
    <span class="tc-tag-list-item">
      <$set name="transclusion" value=<<currentTiddler>>>
      <$macrocall $name="tag-pill-body" tag=<<currentTiddler>> icon={{!!icon}} colour={{!!color}} palette={{$:/palette}} element-tag="""$button""" element-attributes="""popup=<<qualify "$:/state/popup/tag">> dragFilter='[all[current]tagging[]]' tag='span'"""/>
      <$reveal state=<<qualify "$:/state/popup/tag">> type="popup" position="below" animate="yes" class="tc-drop-down">
      <$set name="tv-show-missing-links" value="yes">
      <$transclude tiddler="$:/core/ui/ListItemTemplate"/>
      </$set>
      <$list filter="[all[shadows+tiddlers]tag[$:/tags/TagDropdown]!has[draft.of]]" variable="listItem"> 
      <$transclude tiddler=<<listItem>>/> 
      </$list>
      <hr>
      <$macrocall $name="list-tagged-draggable" tag=<<currentTiddler>> subFilter="tag<__tag__>tag<__ctag__>"/>
      </$reveal>
      </$set>
    </span>
  </$list>
</div>

<div class="twocolumns" style="margin:15px 0;padding:0 0 0 24px;align-items:left;">

{{{ [tag<__tag__>tag<__ctag__>!has[draft.of]sort[]] ||$:/templates/popup}}}

</div>

</$wikify>
</$vars>
\end

