/*
** General
*/

.xp-search a svg {
    width: 1.2em;
    height: 1.2em;
    vertical-align: middle;
}

.xp-search button svg, .xp-search a svg {
    fill: <<colour tiddler-controls-foreground>>;
    height: 1.2em;
    width: 1.2em;
    margin: 0 0.25em;
}

.xp-search button:hover svg, .xp-search a:hover svg {
    fill: <<colour tiddler-controls-foreground-hover>>;
}

.xp-search-results {
    padding: 0 7px 0 14px;
    color: <<colour tab-foreground>>;
    font-size: 0.985rem;
}

.xp-filtersearch button svg, .xp-filtersearch a svg {
    height: 1em;
    width: 1em;
}

.box-list-tags {
    background: <<colour page-background>>;
    border-radius: 2px / 10px;
    padding: 10px;
    width: 100%;
}

.xp-tag-divider {
    border-right: 1px solid <<colour sidebar-tab-divider>>;
    margin-right: 10px;
}

.xp-image-big-muted svg {
    width: 3.5em;
    height: 3.5em;
    fill: <<colour muted-foreground>>;
}

.xp-active-indicator-muted {
    box-shadow: inset 0 -1px <<colour muted-foreground>>;
}

.xp-image-click-popup {
    fill: <<colour muted-foreground>>;
<$reveal state="$:/palette" type="match" text="$:/palettes/Vanilla">
    fill: #aaa;
</$reveal>
}

.tc-link-info-item {
<$list filter="[{$:/palette}get[color-scheme]] +[else[light]match[dark]]" variable="ignore">
    border-color: <<colour tab-divider>> !important;
</$list>
}


/*
** Tag handler
*/

.xp-tag-handler svg {
    height: 1em;
    width: 1em;
    fill: <<colour tiddler-controls-foreground>>;
}

.xp-tag-handler:hover svg {
    fill: <<colour tiddler-controls-foreground-hover>>;
}

.xp-tag-handler-item {
    position: relative;
    display: inline-block;
    float: left;
    vertical-align: middle;
    text-align: left;
    padding: 4px 5px 0 0;
}


.xp-tag-handler-blank {
    padding-left: 2px;
    padding-right: 10px;
}

.xp-tag-handler-dropdown {
    min-width: 117px;
    border: 1px solid <<colour dropdown-border>>;
    border-radius: 6px;
    background-color: <<colour dropdown-background>>;
    margin: 4px 0 0 0;
    padding: 7px 0 7px 0;
    text-shadow: none;
    font-size: 0.9em;
    font-weight: normal;
    line-height: 1.5em;
    color: <<colour tag-foreground>>;
    white-space: nowrap;
    vertical-align: baseline;
}

.xp-tag-handler-dropdown button {
    display: block;
    padding: 0 10px 0 10px;
    width: 100%;
    text-align: left;
    color: <<colour foreground>>;
    line-height: 1.65em;
}

.xp-tag-handler-dropdown button:hover {
    color: <<colour tiddler-link-background>>;
    background-color: <<colour tiddler-link-foreground>>;
    text-decoration: none;
}

.xp-indicator-purple {
    padding-right: 2px;
    fill: purple;
<$list filter="[{$:/palette}get[color-scheme]] +[else[light]match[dark]]" variable="ignore">
    fill: #9966CC;
</$list>
}

.xp-indicator-orange {
    padding-right: 2px;
    fill: orange;
}

.xp-indicator-green {
    padding-right: 2px;
    fill: green;
<$list filter="[{$:/palette}get[color-scheme]] +[else[light]match[dark]]" variable="ignore">
    fill: #99CC66;
</$list>
}

.xp-indicator-gray {
    padding-right: 2px;
    fill: #bbb;
}

.xp-indicator-gray-text {
    padding-right: 10px;
}

.xp-indicator-star {
    fill: <<colour primary>>;
}

@media (min-width: <<sidebarbreakpoint>>) {
    .xp-indicator-journal {
        padding-left: 20px;
    }
}

@media (max-width: <<sidebarbreakpoint>>) {
    .xp-indicator-journal {
        padding-left: 30px;
    }
