*/

<$list filter="[[$:/xp]!has[plugin-type]!type[application/json]]" variable="ignore">

/* $:/_xp/Stylesheet/popup */

.xp-popup {
	min-width: 380px;
	border: 1px solid <<colour dropdown-border>>;
	border-radius: 6px;
	background-color: <<colour dropdown-background>>;
	padding: 7px 0 7px 0;
	margin: 4px 0 0 0;
